class TCPWindow:
    def __init__(self, size=10):
        self.window_size = size
        self.base = 0
        self.next_seq = 0

    def can_send(self) -> bool:
        return self.next_seq - self.base < self.window_size

    def send(self):
        if self.can_send():
            self.next_seq += 1
            return self.next_seq - 1
        return None

    def ack(self, seq_num):
        if seq_num >= self.base:
            self.base = seq_num + 1
